struct GoogleMapView: UIViewRepresentable {
    var center: CLLocationCoordinate2D
    
    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: center.latitude, longitude: center.longitude, zoom: 12)
        let mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.settings.myLocationButton = true
        mapView.isMyLocationEnabled = false
        let marker = GMSMarker(position: center)
        marker.title = "Demo Location"
        marker.snippet = "Investor-ready map integration"
        marker.map = mapView
        return mapView
    }
    
    func updateUIView(_ uiView: GMSMapView, context: Context) {
        uiView.camera = GMSCameraPosition.camera(withLatitude: center.latitude, longitude: center.longitude, zoom: 12)
    }
}

final class PaymentViewModel: ObservableObject {
    @Published var paymentStatus: String = "Ready to pay"
    @Published var isProcessing = false
    
    func processPayment() {
        isProcessing = true
        paymentStatus = "Processing payment..."
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
            self.isProcessing = false
            self.paymentStatus = "Payment complete"
        }
    }
}

